/* Rainbow gradient text with subtle animation */
html,body{
  height:100%;
  margin:0;
  font-family:system-ui, -apple-system, 'Segoe UI', Roboto, 'Helvetica Neue', Arial;
  background: linear-gradient(180deg, #0f172a 0%, #071133 100%);
  color: #ffffff;
}

main{
  height:100%;
  display:flex;
  flex-direction:column;
  justify-content:center;
  align-items:center;
  text-align:center;
  padding:2rem;
}

h1#greeting{
  font-size:clamp(2.5rem, 8vw, 6rem);
  line-height:1;
  margin:0;
  background: linear-gradient(90deg, #ff004c 0%, #ff8a00 16%, #ffec00 33%, #00d084 50%, #0078ff 66%, #6b00ff 83%, #ff2dff 100%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  /* animate background position to create a moving rainbow feel */
  background-size: 200% 200%;
  animation: rainbowShift 6s linear infinite;
  cursor: pointer;
  outline: none;
}

.hint{
  margin-top:1rem;
  opacity:0.8;
  font-size:0.95rem;
}

@keyframes rainbowShift{
  0%{background-position:0% 50%;}
  50%{background-position:100% 50%;}
  100%{background-position:0% 50%;}
}

/* Focus styles for accessibility */
#greeting:focus{
  box-shadow: 0 0 0 4px rgba(255,255,255,0.08);
  border-radius:8px;
}


--- src/server.ts ---
import express from 'express';
import path from 'path';

const app = express();
const port = process.env.PORT ? Number(process.env.PORT) : 3000;

// Serve static files from the public directory (projectRoot/public)
app.use(express.static(path.join(__dirname, '..', 'public')));

// Fallback route to index.html for the root
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, '..', 'public', 'index.html'));
});

app.listen(port, () => {
  console.log(`Hello Rainbow UI dev server running at http://localhost:${port}`);
});


--- tests/mockup.test.ts ---
import fs from 'fs';
import path from 'path';

describe('mockup files', () => {
  test('public/index.html contains Hello World and references assets', () => {
    const htmlPath = path.join(__dirname, '..', 'public', 'index.html');
    const html = fs.readFileSync(htmlPath, 'utf8');
    expect(html).toMatch(/Hello World/);
    expect(html).toMatch(/styles\.css/);
    expect(html).toMatch(/main\.js/);
  });

  test('styles.css contains rainbow animation', () => {
    const cssPath = path.join(__dirname, '..', 'public', 'styles.css');
    const css = fs.readFileSync(cssPath, 'utf8');
    expect(css).toMatch(/@keyframes rainbowShift/);
    expect(css).toMatch(/background: linear-gradient/);
  });
});


